  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedTelegramAccount

// Get default account
export function resolveDefaultTelegramAccountId(cfg: OpenClawConfig): string
```

**Token resolution order:**
1. Environment variable (`TELEGRAM_BOT_TOKEN`)
2. Token file (`tokenFile` config)
3. Config (`botToken` in config)
4. Account-specific overrides in `accounts.<id>.botToken`

---

### **11. Plugin Registration & Types**

From `src/plugins/contracts/registry.ts`:
- Plugins are registered in `BUNDLED_PLUGIN_CONTRACT_SNAPSHOTS`
- Registry maintains mapping of plugin IDs to their provided:
  - `providerIds`
  - `speechProviderIds`
  - `mediaUnderstandingProviderIds`
  - `imageGenerationProviderIds`
  - `webFetchProviderIds`
  - `webSearchProviderIds`
  - `cliBackendIds`
  - `toolNames`

Channel plugins declare their ID in the `channels` field of `openclaw.plugin.json`.

