      pollMaxOptions: 10,         // Max poll options
      shouldSuppressLocalPayloadPrompt,
      beforeDeliverPayload,       // Pre-send hooks
      shouldSkipPlainTextSanitization,
      resolveEffectiveTextChunkLimit: ({ fallbackLimit }) =>
        typeof fallbackLimit === "number" ? Math.min(fallbackLimit, 4096) : 4096,
      sendPayload: async ({...}) => {...},  // Main send function
    },
    attachedResults: {
      channel: "telegram",
      sendText,
      sendMedia,
      sendPoll,
    },
  },
