24	const channel = "nostr" as const;
25	
26	const NOSTR_SETUP_HELP_LINES = [
27	  "Use a Nostr private key in nsec or 64-character hex format.",
28	  "Relay URLs are optional. Leave blank to keep the default relay set.",
29	  "Env vars supported: NOSTR_PRIVATE_KEY (default account only).",
30	  `Docs: ${formatDocsLink("/channels/nostr", "channels/nostr")}`,
31	];
32	
33	const NOSTR_ALLOW_FROM_HELP_LINES = [
34	  "Allowlist Nostr DMs by npub or hex pubkey.",
35	  "Examples:",
36	  "- npub1...",
37	  "- nostr:npub1...",
38	  "- 0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef",
39	  "Multiple entries: comma-separated.",
40	  `Docs: ${formatDocsLink("/channels/nostr", "channels/nostr")}`,
41	];
42	
43	function parseRelayUrls(raw: string): { relays: string[]; error?: string } {
44	  const entries = splitSetupEntries(raw);
45	  const relays: string[] = [];
46	  for (const entry of entries) {
47	    try {
48	      const parsed = new URL(entry);
49	      if (parsed.protocol !== "ws:" && parsed.protocol !== "wss:") {
50	        return { relays: [], error: `Relay must use ws:// or wss:// (${entry})` };
51	      }
52	    } catch {
53	      return { relays: [], error: `Invalid relay URL: ${entry}` };
54	    }
55	    relays.push(entry);
56	  }
57	  return { relays: [...new Set(relays)] };
58	}
59	
60	function parseNostrAllowFrom(raw: string): { entries: string[]; error?: string } {
61	  return parseSetupEntriesWithParser(raw, (entry) => {
62	    const cleaned = entry.replace(/^nostr:/i, "").trim();
63	    try {
64	      return { value: normalizePubkey(cleaned) };
65	    } catch {
66	      return { error: `Invalid Nostr pubkey: ${entry}` };
67	    }
68	  });
69	}
70	
71	const promptNostrAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
72	  channel,
73	  defaultAccountId: DEFAULT_ACCOUNT_ID,
74	  noteTitle: "Nostr allowlist",
75	  noteLines: NOSTR_ALLOW_FROM_HELP_LINES,
76	  message: "Nostr allowFrom",
77	  placeholder: "npub1..., 0123abcd...",
78	  parseEntries: parseNostrAllowFrom,
79	  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
80	});
81	
82	const nostrDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy({
83	  label: "Nostr",
84	  channel,
85	  policyKey: "channels.nostr.dmPolicy",
86	  allowFromKey: "channels.nostr.allowFrom",
87	  getCurrent: (cfg) => cfg.channels?.nostr?.dmPolicy ?? "pairing",
88	  promptAllowFrom: promptNostrAllowFrom,
89	});
90	
91	export const nostrSetupAdapter: ChannelSetupAdapter = {
92	  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
93	  applyAccountName: ({ cfg, name }) =>
