68	    const timer = setTimeout(
69	      () => reject(new Error(`${label} timed out after ${timeoutMs}ms`)),
70	      timeoutMs,
71	    );
72	    promise
73	      .then((result) => {
74	        clearTimeout(timer);
75	        resolve(result);
76	      })
77	      .catch((error) => {
