54	/** Check whether a sender id matches a simple normalized allowlist with wildcard support. */
55	export function isNormalizedSenderAllowed(params: {
56	  senderId: string | number;
57	  allowFrom: Array<string | number>;
58	  stripPrefixRe?: RegExp;
59	}): boolean {
60	  const normalizedAllow = formatAllowFromLowercase({
61	    allowFrom: params.allowFrom,
62	    stripPrefixRe: params.stripPrefixRe,
63	  });
64	  if (normalizedAllow.length === 0) {
65	    return false;
66	  }
67	  if (normalizedAllow.includes("*")) {
68	    return true;
69	  }
70	  const sender = String(params.senderId).trim().toLowerCase();
71	  return normalizedAllow.includes(sender);
72	}
