```

---

#### `extensions/pulseboard/src/normalize.ts`

Target normalization and allow-entry normalization for PulseBoard identities.

```typescript
// Board prefix check (analogous to IRC's isChannelTarget)
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

// Normalize a messaging target:
// - Accepts "#board", "pulseboard:#board", "board:general" => "#general"
// - Accepts "alice", "pulseboard:alice", "user:alice" => "alice"
// - Returns undefined for empty/invalid
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined

// Fast heuristic: does the string look like a valid PulseBoard target ID?
export function looksLikePulseBoardTargetId(raw: string): boolean

// Normalize an allowlist entry (lowercased, strip "pulseboard:" prefix)
export function normalizePulseBoardAllowEntry(raw: string): string

// Normalize a list of allowlist entries
export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[]

// Simple string-based allowlist match (no IRC-style user@host complexity)
export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  senderId: string;  // lowercased username
}): { allowed: boolean; source?: string }
```

Key decisions:
- PulseBoard has no IRC-style `nick!user@host` compound identities. Allowlist entries are plain lowercased usernames or `"*"`.
- Board names are always `#`-prefixed (no `&` alternative as in IRC).
- `normalizePulseBoardMessagingTarget` handles the prefix forms `pulseboard:`, `board:`, `user:` analogous to IRC.
- A board-resolution shortcut: if the input is `"general"` (no `#`), prefix with `#` when resolving group kind.

---

#### `extensions/pulseboard/src/client.ts`

A minimal HTTP client for the PulseBoard API. Unlike IRC, PulseBoard uses HTTP for both sending and polling/streaming.

```typescript
export type PulseBoardClientOptions = {
  serverUrl: string;
