  onMessage?: (message: PulseBoardApiMessage) => void | Promise<void>;
  onError?: (error: Error) => void;
};

export type PulseBoardApiMessage = {
  id: string;
  board?: string;       // present for group messages
  sender: string;       // username
  recipient?: string;   // present for DMs
  text: string;
  timestamp: number;
};

export type PulseBoardClient = {
  isReady: () => boolean;
  sendMessage: (target: string, text: string) => Promise<{ messageId: string }>;
  stop: () => void;
};

// Connect and start polling the /events or /messages endpoint
export async function connectPulseBoardClient(
  options: PulseBoardClientOptions,
): Promise<PulseBoardClient>

// Simple health-check ping (used by probe)
export async function pingPulseBoardHealth(params: {
  serverUrl: string;
  apiToken: string;
  timeoutMs?: number;
}): Promise<{ ok: boolean; latencyMs?: number; error?: string }>
```

Implementation details:
- `connectPulseBoardClient` issues an initial GET to `<serverUrl>/health` to verify credentials before starting the poll loop.
- Polling uses `fetch` with `AbortSignal` propagation. The poll loop hits `GET <serverUrl>/messages?since=<cursor>` on a configurable interval (default 2s).
- `sendMessage` issues `POST <serverUrl>/messages` with `{ board, recipient, text }` JSON body, using `apiToken` in the `Authorization: Bearer <token>` header.
- `pingPulseBoardHealth` is a standalone function (not tied to a connected client) for use from `probe.ts`.

