### Step 3: `src/types.ts`

```typescript
import type { DmPolicy, GroupPolicy, GroupToolPolicyConfig,
  GroupToolPolicyBySenderConfig, MarkdownConfig, OpenClawConfig,
  BaseProbeResult } from "./runtime-api.js";

export type PulseBoardGroupConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  serverUrl?: string;
  apiToken?: string;
  apiTokenFile?: string;
