### Step 12: `src/policy.ts`

```typescript
import type { PulseBoardGroupConfig } from "./types.js";

export type PulseBoardGroupMatch = {
  groupConfig?: PulseBoardGroupConfig;
  wildcardConfig?: PulseBoardGroupConfig;
};

export function resolvePulseBoardGroupMatch(params: {
  boards?: Record<string, PulseBoardGroupConfig | undefined>;
  target: string;
}): PulseBoardGroupMatch {
  const boards = params.boards ?? {};
  const exact = boards[params.target];
  const wildcard = boards["*"];
  return { groupConfig: exact, wildcardConfig: wildcard };
}

export function resolvePulseBoardRequireMention(params: {
  groupConfig?: PulseBoardGroupConfig;
  wildcardConfig?: PulseBoardGroupConfig;
}): boolean {
  const { groupConfig, wildcardConfig } = params;
  if (typeof groupConfig?.requireMention === "boolean") return groupConfig.requireMention;
  if (typeof wildcardConfig?.requireMention === "boolean") return wildcardConfig.requireMention;
  return true; // safe default for group chats
}
```

### Step 13: `src/monitor.ts`

Simulated polling monitor — no real WebSocket/HTTP long-poll since PulseBoard is fictional. The monitor starts, logs connectivity, and returns a stop handle. A real implementation would open a WebSocket connection here.

```typescript
import { dispatchInboundDirectDmWithRuntime } from "openclaw/plugin-sdk/channel-inbound";
import { resolvePulseBoardAccount } from "./accounts.js";
import { isBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number }) => void;
};

export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need serverUrl and apiToken in channels.pulseboard).`,
    );
  }

  // In a real implementation, open a WebSocket to account.serverUrl here.
  // For the fictional plugin, we simply hold an open handle until aborted.
  const abortSignal = opts.abortSignal;

  return new Promise<{ stop: () => void }>((resolve) => {
    let stopped = false;

    function stop() {
      stopped = true;
      // Close WebSocket connection here in a real implementation.
    }

    if (abortSignal?.aborted) {
      resolve({ stop });
      return;
    }

    abortSignal?.addEventListener("abort", () => {
      if (!stopped) stop();
    });

    // Resolve immediately with the stop handle (simulated running connection).
    resolve({ stop });
  });
}
```

> **Note on `dispatchInboundDirectDmWithRuntime`:** The exact import path (`openclaw/plugin-sdk/channel-inbound`) must be confirmed at implementation time. In the Nostr plugin it is imported from `"../runtime-api.js"`. At implementation time, find the correct generic subpath by checking the package exports or following the Nostr pattern. This is used for when real inbound messages arrive.

### Step 14: `src/setup-core.ts`

```typescript
import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import { normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import {
  applyAccountNameToChannelSection,
  createSetupInputPresenceValidator,
  patchScopedAccountConfig,
} from "openclaw/plugin-sdk/setup";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

const channel = "pulseboard" as const;

export function updatePulseBoardAccountConfig(
  cfg: CoreConfig,
  accountId: string,
  patch: Partial<PulseBoardAccountConfig>,
): CoreConfig {
  return patchScopedAccountConfig({
    cfg,
    channelKey: channel,
    accountId,
    patch,
    ensureChannelEnabled: false,
    ensureAccountEnabled: false,
  }) as CoreConfig;
}

type PulseBoardSetupInput = {
  serverUrl?: string;
  apiToken?: string;
  username?: string;
  useEnv?: boolean;
};

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: ({ accountId }) => normalizeAccountId(accountId),
  applyAccountName: ({ cfg, accountId, name }) =>
    applyAccountNameToChannelSection({ cfg, channelKey: channel, accountId, name }),
  validateInput: createSetupInputPresenceValidator({
    whenNotUseEnv: [
      { someOf: ["serverUrl"], message: "PulseBoard requires serverUrl." },
      { someOf: ["apiToken"], message: "PulseBoard requires apiToken." },
    ],
  }),
  applyAccountConfig: ({ cfg, accountId, input }) => {
    const setupInput = input as PulseBoardSetupInput;
    const namedConfig = applyAccountNameToChannelSection({
      cfg,
      channelKey: channel,
      accountId,
      name: (setupInput as { name?: string }).name,
    });
    const patch: Partial<PulseBoardAccountConfig> = {
      enabled: true,
      serverUrl: setupInput.serverUrl?.trim(),
      apiToken: setupInput.useEnv ? undefined : setupInput.apiToken?.trim(),
      username: setupInput.username?.trim() || undefined,
    };
    return patchScopedAccountConfig({
      cfg: namedConfig,
      channelKey: channel,
      accountId,
      patch,
    }) as CoreConfig;
  },
};
```

