  formatDocsLink,
  mergeAllowFromEntries,
  parseSetupEntriesWithParser,
  patchTopLevelChannelConfigSection,
} from "openclaw/plugin-sdk/setup";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
import { hasConfiguredSecretInput } from "openclaw/plugin-sdk/secret-input";
import { normalizePulseBoardAllowEntry } from "./normalize.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import { pulseBoardSetupAdapter } from "./setup-core.js";

const channel = "pulseboard" as const;

const HELP_LINES = [
  "Enter your PulseBoard server URL and API token.",
  "Env var supported: PULSEBOARD_API_TOKEN (default account only).",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by username.",
  "Examples: alice, @bob",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

function parsePulseBoardAllowFrom(raw: string): { entries: string[]; error?: string } {
  return parseSetupEntriesWithParser(raw, (entry) => {
    const normalized = normalizePulseBoardAllowEntry(entry);
    if (!normalized) return { error: `Invalid PulseBoard username: ${entry}` };
    return { value: normalized };
  });
}

const promptAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
  channel,
  defaultAccountId: DEFAULT_ACCOUNT_ID,
  noteTitle: "PulseBoard allowlist",
  noteLines: ALLOW_FROM_HELP_LINES,
  message: "PulseBoard allowFrom (username or @username)",
  placeholder: "alice, @bob",
  parseEntries: parsePulseBoardAllowFrom,
  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
});

const pulseBoardDmPolicy = createTopLevelChannelDmPolicy({
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg.channels as Record<string, unknown> | undefined)?.pulseboard?.dmPolicy ?? "pairing",
  promptAllowFrom,
});

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs serverUrl and apiToken",
    configuredHint: "configured",
    unconfiguredHint: "needs serverUrl and apiToken",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) => resolvePulseBoardAccount({ cfg }).configured,
    resolveExtraStatusLines: ({ cfg }) => {
      const account = resolvePulseBoardAccount({ cfg });
      return [`Server: ${account.serverUrl || "(not set)"}`];
    },
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: HELP_LINES,
  },
  envShortcut: {
    prompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
    preferredEnvVar: "PULSEBOARD_API_TOKEN",
    isAvailable: ({ cfg, accountId }) =>
      accountId === DEFAULT_ACCOUNT_ID &&
      Boolean(process.env.PULSEBOARD_API_TOKEN?.trim()) &&
      !hasConfiguredSecretInput(resolvePulseBoardAccount({ cfg, accountId }).config.apiToken),
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, clearFields: ["apiToken"], patch: {} }),
  },
  credentials: [
    {
      inputKey: "apiToken",
      providerHint: channel,
      credentialLabel: "API token",
      preferredEnvVar: "PULSEBOARD_API_TOKEN",
      helpTitle: "PulseBoard API token",
      helpLines: HELP_LINES,
      envPrompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
      keepPrompt: "PulseBoard API token already configured. Keep it?",
      inputPrompt: "PulseBoard API token",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: hasConfiguredSecretInput(account.config.apiToken),
          resolvedValue: account.config.apiToken,
          envValue: process.env.PULSEBOARD_API_TOKEN?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, clearFields: ["apiToken"], patch: {} }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, patch: { apiToken: resolvedValue } }),
    },
  ],
  textInputs: [
    {
      inputKey: "serverUrl",
      message: "PulseBoard server URL",
      placeholder: "https://boards.example.com",
      required: true,
      applyEmptyValue: false,
      helpTitle: "PulseBoard server URL",
      helpLines: ["The base URL of your PulseBoard instance."],
      currentValue: ({ cfg, accountId }) => resolvePulseBoardAccount({ cfg, accountId }).serverUrl,
      keepPrompt: (value) => `Server URL set (${value}). Keep it?`,
      validate: ({ value }) => {
        try { new URL(value); return undefined; } catch { return "Invalid URL."; }
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({ cfg, channel, enabled: true, patch: { serverUrl: value.trim() } }),
    },
  ],
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) =>
    patchTopLevelChannelConfigSection({ cfg, channel, patch: { enabled: false } }),
};

export { pulseBoardSetupAdapter };
```

### Step 16: `src/channel.ts` — The Main Plugin

This is the core file. It wires all the pieces together using `createChatChannelPlugin()`.

```typescript
import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import { formatNormalizedAllowFromEntries } from "openclaw/plugin-sdk/allow-from";
import {
  adaptScopedAccountAccessor,
  createScopedChannelConfigAdapter,
  createScopedDmSecurityResolver,
} from "openclaw/plugin-sdk/channel-config-helpers";
import {
  composeAccountWarningCollectors,
  createAllowlistProviderOpenWarningCollector,
} from "openclaw/plugin-sdk/channel-policy";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  createChannelDirectoryAdapter,
  createResolvedDirectoryEntriesLister,
} from "openclaw/plugin-sdk/directory-runtime";
import { runStoppablePassiveMonitor } from "openclaw/plugin-sdk/extension-shared";
import {
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";

import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
  type ResolvedPulseBoardAccount,
} from "./accounts.js";
import { PulseBoardChannelConfigSchema } from "./config-schema.js";
import { monitorPulseBoardProvider } from "./monitor.js";
import {
  isBoardTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardMessagingTarget,
} from "./normalize.js";
import { resolvePulseBoardGroupMatch, resolvePulseBoardRequireMention } from "./policy.js";
import { probePulseBoard } from "./probe.js";
import { sendMessagePulseBoard } from "./send.js";
import { pulseBoardSetupAdapter } from "./setup-core.js";
import { pulseBoardSetupWizard } from "./setup-surface.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

// --- Import shared runtime helpers ---
// These are re-exported from openclaw/plugin-sdk/* subpaths.
// At implementation time, confirm the exact subpath by checking the
// openclaw package exports or following the IRC/Nostr import pattern.
import {
  DEFAULT_ACCOUNT_ID,
  getChatChannelMeta,
  PAIRING_APPROVED_MESSAGE,
  chunkTextForOutbound,
  buildBaseChannelStatusSummary,
  createAccountStatusSink,
  type ChannelPlugin,
} from "openclaw/plugin-sdk/channel-plugin-common";
import { getPulseBoardRuntime } from "./runtime.js";

const meta = getChatChannelMeta("pulseboard");

// Directory listing helpers
const listPulseBoardDirectoryPeers = createResolvedDirectoryEntriesLister<ResolvedPulseBoardAccount>({
  kind: "user",
  resolveAccount: adaptScopedAccountAccessor(resolvePulseBoardAccount),
  resolveSources: (account) => [
    account.config.allowFrom ?? [],
    account.config.groupAllowFrom ?? [],
    ...Object.values(account.config.boards ?? {}).map((board) => board?.allowFrom ?? []),
  ],
  normalizeId: (entry) => normalizePulseBoardAllowEntry(entry) || null,
});

const listPulseBoardDirectoryGroups = createResolvedDirectoryEntriesLister<ResolvedPulseBoardAccount>({
  kind: "group",
  resolveAccount: adaptScopedAccountAccessor(resolvePulseBoardAccount),
  resolveSources: (account) => [Object.keys(account.config.boards ?? {})],
  normalizeId: (entry) => {
    const normalized = normalizePulseBoardMessagingTarget(entry);
    return normalized && isBoardTarget(normalized) ? normalized : null;
  },
});

// Config adapter (scoped, multi-account)
const pulseBoardConfigAdapter = createScopedChannelConfigAdapter<
  ResolvedPulseBoardAccount, ResolvedPulseBoardAccount, CoreConfig
>({
  sectionKey: "pulseboard",
  listAccountIds: listPulseBoardAccountIds,
  resolveAccount: adaptScopedAccountAccessor(resolvePulseBoardAccount),
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  clearBaseFields: ["name", "serverUrl", "apiToken", "apiTokenFile", "username"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    formatNormalizedAllowFromEntries({ allowFrom, normalizeEntry: normalizePulseBoardAllowEntry }),
  resolveDefaultTo: (account) => account.config.defaultTo,
});

// DM security
const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  normalizeEntry: (raw) => normalizePulseBoardAllowEntry(raw),
});

// Security warnings
const collectPulseBoardGroupPolicyWarnings =
  createAllowlistProviderOpenWarningCollector<ResolvedPulseBoardAccount>({
    providerConfigPresent: (cfg) => (cfg as CoreConfig).channels?.pulseboard !== undefined,
    resolveGroupPolicy: (account) => account.config.groupPolicy,
    buildOpenWarning: {
      surface: "PulseBoard boards",
      openBehavior: "allows all boards and senders (mention-gated)",
      remediation: 'Prefer channels.pulseboard.groupPolicy="allowlist" with channels.pulseboard.boards',
    },
  });

const collectPulseBoardSecurityWarnings = composeAccountWarningCollectors<
  ResolvedPulseBoardAccount, { account: ResolvedPulseBoardAccount; cfg: CoreConfig }
>(collectPulseBoardGroupPolicyWarnings);

// Plugin
export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount, PulseBoardProbe> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: { ...meta, quickstartAllowFrom: true },
      setup: pulseBoardSetupAdapter,
      setupWizard: pulseBoardSetupWizard,
      capabilities: {
        chatTypes: ["direct", "group"],
        media: false,
        blockStreaming: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: PulseBoardChannelConfigSchema,
      config: {
        ...pulseBoardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) =>
          describeAccountSnapshot({
            account,
            configured: account.configured,
            extra: {
              serverUrl: account.serverUrl,
              username: account.username,
              apiTokenSource: account.apiTokenSource,
            },
          }),
      },
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => {
          const account = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
          if (!groupId) return true;
          const match = resolvePulseBoardGroupMatch({ boards: account.config.boards, target: groupId });
          return resolvePulseBoardRequireMention(match);
        },
        resolveToolPolicy: ({ cfg, accountId, groupId }) => {
          const account = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
          if (!groupId) return undefined;
          const match = resolvePulseBoardGroupMatch({ boards: account.config.boards, target: groupId });
          return match.groupConfig?.tools ?? match.wildcardConfig?.tools;
        },
      },
      messaging: {
        normalizeTarget: normalizePulseBoardMessagingTarget,
        targetResolver: {
          looksLikeId: looksLikePulseBoardTargetId,
          hint: "<#board|username>",
        },
      },
      resolver: {
        resolveTargets: async ({ inputs, kind }) =>
          inputs.map((input) => {
            const normalized = normalizePulseBoardMessagingTarget(input);
            if (!normalized) return { input, resolved: false, note: "invalid PulseBoard target" };
            if (kind === "group") {
              const boardId = isBoardTarget(normalized) ? normalized : `#${normalized}`;
              return { input, resolved: true, id: boardId, name: boardId };
            }
            if (isBoardTarget(normalized)) return { input, resolved: false, note: "expected user target" };
            return { input, resolved: true, id: normalized, name: normalized };
          }),
      },
      directory: createChannelDirectoryAdapter({
        listPeers: async (params) => listPulseBoardDirectoryPeers(params),
        listGroups: async (params) => {
          const entries = await listPulseBoardDirectoryGroups(params);
          return entries.map((entry) => ({ ...entry, name: entry.id }));
        },
      }),
      status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount, PulseBoardProbe>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ account, snapshot }) => ({
          ...buildBaseChannelStatusSummary(snapshot),
          serverUrl: account.serverUrl,
          username: account.username,
          probe: snapshot.probe,
          lastProbeAt: snapshot.lastProbeAt ?? null,
        }),
        probeAccount: async ({ cfg, account, timeoutMs }) =>
          probePulseBoard(cfg as CoreConfig, { accountId: account.accountId, timeoutMs }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            username: account.username,
            apiTokenSource: account.apiTokenSource,
          },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          const statusSink = createAccountStatusSink({
            accountId: ctx.accountId,
            setStatus: ctx.setStatus,
          });
          if (!account.configured) {
            throw new Error(
              `PulseBoard is not configured for account "${account.accountId}" (need serverUrl and apiToken in channels.pulseboard).`,
            );
          }
          ctx.log?.info(
            `[${account.accountId}] starting PulseBoard provider (${account.serverUrl})`,
          );
          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () =>
              monitorPulseBoardProvider({
                accountId: account.accountId,
                config: ctx.cfg as CoreConfig,
                abortSignal: ctx.abortSignal,
                statusSink,
              }),
          });
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseBoardUser",
        message: PAIRING_APPROVED_MESSAGE,
        normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry),
        notify: async ({ id, message }) => {
          await sendMessagePulseBoard(id, message);
        },
      },
    },
    security: {
      resolveDmPolicy: resolvePulseBoardDmPolicy,
      collectWarnings: collectPulseBoardSecurityWarnings,
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        chunker: chunkTextForOutbound,
        chunkerMode: "markdown",
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ cfg, to, text, accountId, replyToId }) =>
          sendMessagePulseBoard(to, text, {
            cfg: cfg as CoreConfig,
            accountId: accountId ?? undefined,
            replyToId: replyToId ?? undefined,
          }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
          sendMessagePulseBoard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text, {
            cfg: cfg as CoreConfig,
            accountId: accountId ?? undefined,
            replyToId: replyToId ?? undefined,
          }),
      },
    },
  });
```

