### Step 3: `src/types.ts`

```typescript
import type { DmPolicy, GroupPolicy, GroupToolPolicyConfig,
  GroupToolPolicyBySenderConfig, MarkdownConfig, OpenClawConfig,
  BaseProbeResult } from "./runtime-api.js";

export type PulseBoardGroupConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  serverUrl?: string;
  apiToken?: string;
  apiTokenFile?: string;
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  boards?: Record<string, PulseBoardGroupConfig>;   // keyed by board name
  markdown?: MarkdownConfig;
  textChunkLimit?: number;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export type PulseBoardInboundMessage = {
  messageId: string;
  /** Conversation peer id: board name for groups, sender username for DMs. */
  target: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

export type PulseBoardProbe = BaseProbeResult<string> & {
  serverUrl: string;
  latencyMs?: number;
};
```

**Key:** `BaseProbeResult` is from `openclaw/plugin-sdk/channel-status`.

### Step 4: `src/runtime-api.ts`

Aggregating barrel for commonly needed SDK types and helpers. Since there is no `openclaw/plugin-sdk/pulseboard` subpath, this re-exports from generic SDK subpaths:

```typescript
