### Step 8: `src/normalize.ts`

```typescript
// Board targets are #board-name; DM targets are username or @username.

export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) return undefined;
  let target = trimmed;
  // Strip provider prefix
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }
  // Handle channel: prefix
  if (target.toLowerCase().startsWith("channel:") || target.toLowerCase().startsWith("board:")) {
    const rest = target.includes(":") ? target.slice(target.indexOf(":") + 1).trim() : target;
    target = rest.startsWith("#") ? rest : `#${rest}`;
  }
  // Handle user: prefix
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }
  // Normalize @username to username for DMs
  if (!isBoardTarget(target) && target.startsWith("@")) {
    target = target.slice(1);
  }
  if (!target || !looksLikePulseBoardTargetId(target)) return undefined;
  return target;
}

const VALID_TARGET = /^[^\s]+$/u;

export function looksLikePulseBoardTargetId(raw: string): boolean {
  return Boolean(raw.trim()) && VALID_TARGET.test(raw.trim());
}

export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) return "";
  if (value.startsWith("pulseboard:")) value = value.slice("pulseboard:".length);
  if (value.startsWith("user:")) value = value.slice("user:".length);
  if (value.startsWith("@")) value = value.slice(1);
  return value.trim();
}
