/**
 * Target normalization for PulseBoard.
 *
 * Boards: #board-name (group targets)
 * DMs:    username or @username (direct targets, stored without @)
 */

export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

const VALID_TARGET_PATTERN = /^[^\s]+$/u;

export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  return Boolean(trimmed) && VALID_TARGET_PATTERN.test(trimmed);
}

export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }

  let target = trimmed;

  // Strip provider prefix (pulseboard:)
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // Handle channel: or board: prefix — ensure # prefix
  const lower = target.toLowerCase();
  if (lower.startsWith("channel:") || lower.startsWith("board:")) {
    const colonIndex = target.indexOf(":");
    const rest = target.slice(colonIndex + 1).trim();
    target = rest.startsWith("#") ? rest : `#${rest}`;
  } else if (lower.startsWith("user:")) {
    // Strip user: prefix for DM targets
    target = target.slice("user:".length).trim();
    // Normalize @username → username for DMs
    if (target.startsWith("@")) {
      target = target.slice(1);
    }
  } else if (!isBoardTarget(target) && target.startsWith("@")) {
    // @username shorthand for DMs
    target = target.slice(1);
  }

  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }

  return target;
}

export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  // Strip leading @ for DM allow entries
  if (value.startsWith("@")) {
    value = value.slice(1);
  }
  return value.trim();
}

export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((entry) => normalizePulseBoardAllowEntry(String(entry))).filter(Boolean);
}

