import type { PulseBoardBoardConfig } from "./types.js";

export type PulseBoardBoardMatch = {
  boardConfig?: PulseBoardBoardConfig;
  wildcardConfig?: PulseBoardBoardConfig;
};

/**
 * Resolve the board config and wildcard config for a given board target.
 * The wildcard key "*" applies to all boards not explicitly configured.
 */
export function resolvePulseBoardBoardMatch(params: {
  boards?: Record<string, PulseBoardBoardConfig | undefined>;
  target: string;
}): PulseBoardBoardMatch {
  const boards = params.boards ?? {};
  return {
    boardConfig: boards[params.target],
    wildcardConfig: boards["*"],
  };
}

/**
 * Resolve whether a mention is required in a board.
 * Checks exact board config first, then wildcard, then defaults to true.
 */
export function resolvePulseBoardRequireMention(params: {
  boardConfig?: PulseBoardBoardConfig;
  wildcardConfig?: PulseBoardBoardConfig;
}): boolean {
  const { boardConfig, wildcardConfig } = params;
  if (typeof boardConfig?.requireMention === "boolean") {
    return boardConfig.requireMention;
  }
  if (typeof wildcardConfig?.requireMention === "boolean") {
    return wildcardConfig.requireMention;
  }
  // Safe default: require mention in board chats
  return true;
}

