  replyToId?: string;
};

/**
 * Send a message to a PulseBoard target (board or DM).
 *
 * Since PulseBoard is fictional, outbound delivery is simulated — a real
 * integration would POST to <serverUrl>/messages or open a WebSocket here.
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" ` +
        "(need serverUrl and apiToken in channels.pulseboard).",
    );
  }

  const target = normalizePulseBoardMessagingTarget(to);
  if (!target) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const tableMode = resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  const payload = opts.replyToId ? `${prepared}\n\n[reply:${opts.replyToId}]` : prepared;

  if (!payload.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  // Record outbound activity for status tracking.
  runtime.channel.activity.record({
    channel: "pulseboard",
    accountId: account.accountId,
    direction: "outbound",
  });

  // Simulated delivery — construct a deterministic-ish message ID.
  const messageId = `pb-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  return attachChannelToResult("pulseboard", { to: target, messageId });
}

