import { resolvePulseBoardAccount } from "./accounts.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number }) => void;
};

/**
 * Start monitoring a PulseBoard account for inbound messages.
 *
 * In a production integration this function would open a WebSocket to
 * `<serverUrl>/ws` (authenticated with the API token), subscribe to board and
 * DM events, and call dispatchInboundDirectDmWithRuntime / the group
 * equivalent for each arriving message.
 *
 * PulseBoard is fictional, so this implementation simply validates configuration
 * and holds an open lifecycle handle until the abort signal fires. Drop-in
 * replacement: swap the body below for a real WebSocket client.
 */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" ` +
        "(need serverUrl and apiToken in channels.pulseboard).",
    );
  }

  const abortSignal = opts.abortSignal;
  let stopped = false;

  function stop() {
    stopped = true;
    // A real implementation would close the WebSocket here.
  }

  return new Promise<{ stop: () => void }>((resolve) => {
    if (abortSignal?.aborted) {
      resolve({ stop });
      return;
    }

    abortSignal?.addEventListener("abort", () => {
      if (!stopped) {
        stop();
      }
    });

    // Simulated "connected" state — resolve immediately.
    resolve({ stop });
  });
}

