import type { DmPolicy, GroupPolicy, OpenClawConfig } from "./runtime-api.js";

// Inline types that are only available via channel-specific SDK facades (like
// openclaw/plugin-sdk/irc). We define them locally to avoid reaching into
// restricted surfaces.

/** Minimal probe result base — mirrors channels/plugins/types.core.ts:BaseProbeResult. */
export type BaseProbeResult<TError = string | null> = {
  ok: boolean;
  error?: TError;
};

export type GroupToolPolicyConfig = {
  allow?: string[];
  alsoAllow?: string[];
  deny?: string[];
};

export type GroupToolPolicyBySenderConfig = Record<string, GroupToolPolicyConfig>;

export type MarkdownConfig = {
  /** Table rendering mode (off|bullets|code|block). */
  tables?: "off" | "bullets" | "code" | "block";
};

// --- PulseBoard-specific types ---

export type PulseBoardBoardConfig = {
  /** Require @mention before responding in this board. Default: true. */
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** Base URL of the PulseBoard server (e.g. https://boards.example.com). */
  serverUrl?: string;
  /** API token for authenticating with the PulseBoard server. */
  apiToken?: string;
  /** Path to a file containing the API token (alternative to apiToken). */
  apiTokenFile?: string;
  /** Username/handle for this account. */
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  /** Per-board config. Keys are board names (e.g. "#general"). */
  boards?: Record<string, PulseBoardBoardConfig>;
  markdown?: MarkdownConfig;
  /** Override the default 4000-character text chunk limit. */
  textChunkLimit?: number;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export type PulseBoardInboundMessage = {
  messageId: string;
  /** Conversation peer: board name for groups, sender username for DMs. */
  target: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

export type PulseBoardProbe = BaseProbeResult<string> & {
  serverUrl: string;
  latencyMs?: number;
};

