import { describe, expect, it } from "vitest";
import {
  isBoardTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardAllowlist,
  normalizePulseBoardMessagingTarget,
} from "./normalize.js";

describe("isBoardTarget", () => {
  it("returns true for #-prefixed targets", () => {
    expect(isBoardTarget("#general")).toBe(true);
    expect(isBoardTarget("#my-board")).toBe(true);
  });

  it("returns false for non-board targets", () => {
    expect(isBoardTarget("alice")).toBe(false);
    expect(isBoardTarget("@alice")).toBe(false);
    expect(isBoardTarget("")).toBe(false);
  });
});

describe("looksLikePulseBoardTargetId", () => {
  it("returns true for valid targets", () => {
    expect(looksLikePulseBoardTargetId("alice")).toBe(true);
    expect(looksLikePulseBoardTargetId("#general")).toBe(true);
    expect(looksLikePulseBoardTargetId("user123")).toBe(true);
  });

  it("returns false for empty or whitespace", () => {
    expect(looksLikePulseBoardTargetId("")).toBe(false);
    expect(looksLikePulseBoardTargetId("   ")).toBe(false);
  });

  it("returns false when target contains whitespace", () => {
    expect(looksLikePulseBoardTargetId("alice bob")).toBe(false);
    expect(looksLikePulseBoardTargetId("#my board")).toBe(false);
  });
});

describe("normalizePulseBoardMessagingTarget", () => {
  it("passes through plain usernames", () => {
    expect(normalizePulseBoardMessagingTarget("alice")).toBe("alice");
  });

  it("strips @ from DM targets", () => {
    expect(normalizePulseBoardMessagingTarget("@alice")).toBe("alice");
  });

  it("passes through board targets", () => {
    expect(normalizePulseBoardMessagingTarget("#general")).toBe("#general");
  });

  it("strips pulseboard: provider prefix", () => {
    expect(normalizePulseBoardMessagingTarget("pulseboard:alice")).toBe("alice");
    expect(normalizePulseBoardMessagingTarget("pulseboard:#general")).toBe("#general");
    expect(normalizePulseBoardMessagingTarget("PULSEBOARD:alice")).toBe("alice");
  });

  it("handles board: prefix", () => {
    expect(normalizePulseBoardMessagingTarget("board:general")).toBe("#general");
    expect(normalizePulseBoardMessagingTarget("board:#general")).toBe("#general");
  });

  it("handles channel: prefix", () => {
    expect(normalizePulseBoardMessagingTarget("channel:general")).toBe("#general");
    expect(normalizePulseBoardMessagingTarget("channel:#news")).toBe("#news");
  });

  it("handles user: prefix", () => {
    expect(normalizePulseBoardMessagingTarget("user:alice")).toBe("alice");
    expect(normalizePulseBoardMessagingTarget("user:@alice")).toBe("alice");
  });

  it("trims surrounding whitespace", () => {
    expect(normalizePulseBoardMessagingTarget("  alice  ")).toBe("alice");
    expect(normalizePulseBoardMessagingTarget("  #general  ")).toBe("#general");
  });

  it("returns undefined for empty input", () => {
    expect(normalizePulseBoardMessagingTarget("")).toBeUndefined();
    expect(normalizePulseBoardMessagingTarget("   ")).toBeUndefined();
  });

  it("returns undefined for targets with internal whitespace", () => {
    expect(normalizePulseBoardMessagingTarget("alice bob")).toBeUndefined();
  });
});

describe("normalizePulseBoardAllowEntry", () => {
  it("lowercases entries", () => {
    expect(normalizePulseBoardAllowEntry("Alice")).toBe("alice");
    expect(normalizePulseBoardAllowEntry("BOB")).toBe("bob");
  });

  it("strips leading @", () => {
    expect(normalizePulseBoardAllowEntry("@alice")).toBe("alice");
  });

  it("strips pulseboard: prefix", () => {
    expect(normalizePulseBoardAllowEntry("pulseboard:alice")).toBe("alice");
  });

  it("strips user: prefix", () => {
    expect(normalizePulseBoardAllowEntry("user:alice")).toBe("alice");
  });

  it("returns empty string for blank input", () => {
    expect(normalizePulseBoardAllowEntry("")).toBe("");
    expect(normalizePulseBoardAllowEntry("   ")).toBe("");
  });
});

describe("normalizePulseBoardAllowlist", () => {
  it("normalizes and filters blank entries", () => {
    expect(normalizePulseBoardAllowlist(["Alice", "@bob", ""])).toEqual(["alice", "bob"]);
  });

  it("handles undefined", () => {
    expect(normalizePulseBoardAllowlist(undefined)).toEqual([]);
  });

  it("handles numeric entries", () => {
    expect(normalizePulseBoardAllowlist([123, "alice"])).toEqual(["123", "alice"]);
  });
});

