import { describe, expect, it } from "vitest";
import {
  PulseBoardAccountSchema,
  PulseBoardAccountSchemaBase,
  PulseBoardChannelConfigSchema,
  PulseBoardConfigSchema,
} from "./config-schema.js";

describe("PulseBoardConfigSchema", () => {
  it("accepts a minimal valid config", () => {
    const result = PulseBoardConfigSchema.safeParse({
      serverUrl: "https://boards.example.com",
      apiToken: "tok-abc123",
    });
    expect(result.success).toBe(true);
  });

  it("accepts an empty object", () => {
    const result = PulseBoardConfigSchema.safeParse({});
    expect(result.success).toBe(true);
  });

  it("applies dmPolicy default of pairing", () => {
    const parsed = PulseBoardConfigSchema.parse({});
    expect(parsed.dmPolicy).toBe("pairing");
  });

  it("applies groupPolicy default of allowlist", () => {
    const parsed = PulseBoardConfigSchema.parse({});
    expect(parsed.groupPolicy).toBe("allowlist");
  });

  it("accepts all top-level account fields", () => {
    const parsed = PulseBoardConfigSchema.parse({
      name: "Main",
      enabled: true,
      serverUrl: "https://boards.example.com",
      apiToken: "tok-abc123",
      apiTokenFile: "/run/secrets/token",
      username: "claw-bot",
      dmPolicy: "allowlist",
      allowFrom: ["alice", "bob"],
      defaultTo: "alice",
      groupPolicy: "allowlist",
      groupAllowFrom: ["alice"],
      textChunkLimit: 2000,
    });

    expect(parsed.serverUrl).toBe("https://boards.example.com");
    expect(parsed.apiToken).toBe("tok-abc123");
    expect(parsed.username).toBe("claw-bot");
    expect(parsed.dmPolicy).toBe("allowlist");
    expect(parsed.allowFrom).toEqual(["alice", "bob"]);
    expect(parsed.textChunkLimit).toBe(2000);
  });

  it("accepts named accounts", () => {
    const parsed = PulseBoardConfigSchema.parse({
      accounts: {
        work: {
          serverUrl: "https://work.boards.com",
          apiToken: "tok-work",
        },
        personal: {
          serverUrl: "https://personal.boards.com",
          apiToken: "tok-personal",
        },
      },
    });

    expect(parsed.accounts?.work?.serverUrl).toBe("https://work.boards.com");
    expect(parsed.accounts?.personal?.apiToken).toBe("tok-personal");
  });

  it("accepts defaultAccount", () => {
    const parsed = PulseBoardConfigSchema.parse({
      defaultAccount: "work",
      accounts: { work: {} },
    });

    expect(parsed.defaultAccount).toBe("work");
  });

  it("accepts numeric allowFrom and groupAllowFrom entries", () => {
    const parsed = PulseBoardConfigSchema.parse({
      dmPolicy: "allowlist",
      allowFrom: [123, "alice"],
      groupAllowFrom: [456, "bob"],
    });

    expect(parsed.allowFrom).toEqual([123, "alice"]);
    expect(parsed.groupAllowFrom).toEqual([456, "bob"]);
  });

  it("accepts boards with requireMention and tools", () => {
    const parsed = PulseBoardConfigSchema.parse({
      boards: {
        "#ops": {
          requireMention: true,
          enabled: true,
          allowFrom: ["alice"],
          systemPrompt: "You are an ops bot.",
        },
        "*": {
          requireMention: false,
        },
      },
    });

    expect(parsed.boards?.["#ops"]?.requireMention).toBe(true);
    expect(parsed.boards?.["#ops"]?.allowFrom).toEqual(["alice"]);
    expect(parsed.boards?.["*"]?.requireMention).toBe(false);
  });

  it("accepts numeric board allowFrom entries", () => {
    const parsed = PulseBoardConfigSchema.parse({
      boards: {
        "#ops": {
          allowFrom: [42, "alice"],
        },
      },
    });

    expect(parsed.boards?.["#ops"]?.allowFrom).toEqual([42, "alice"]);
  });

  it("rejects unknown top-level fields (strict)", () => {
    const result = PulseBoardConfigSchema.safeParse({
      unknownField: "bad",
    });
    expect(result.success).toBe(false);
  });

  it("rejects textChunkLimit above 4000", () => {
    const result = PulseBoardConfigSchema.safeParse({
      textChunkLimit: 5000,
    });
    expect(result.success).toBe(false);
  });

  it("rejects textChunkLimit below 1", () => {
    const result = PulseBoardConfigSchema.safeParse({
      textChunkLimit: 0,
    });
    expect(result.success).toBe(false);
  });

  it("rejects non-integer textChunkLimit", () => {
    const result = PulseBoardConfigSchema.safeParse({
      textChunkLimit: 100.5,
    });
    expect(result.success).toBe(false);
  });

  it("rejects invalid serverUrl", () => {
    const result = PulseBoardConfigSchema.safeParse({
      serverUrl: "not-a-url",
    });
    expect(result.success).toBe(false);
  });

  it('rejects dmPolicy="open" without allowFrom including "*"', () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["alice"],
    });
    expect(result.success).toBe(false);
    if (!result.success) {
      const paths = result.error.issues.map((i) => i.path.join("."));
      expect(paths).toContain("allowFrom");
    }
  });

  it('accepts dmPolicy="open" with allowFrom including "*"', () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["*"],
    });
    expect(result.success).toBe(true);
  });
});

describe("PulseBoardAccountSchema", () => {
  it("accepts a minimal valid account", () => {
    const result = PulseBoardAccountSchema.safeParse({
      serverUrl: "https://boards.example.com",
      apiToken: "tok-abc",
    });
    expect(result.success).toBe(true);
  });

  it("applies defaults independently", () => {
    const parsed = PulseBoardAccountSchema.parse({});
    expect(parsed.dmPolicy).toBe("pairing");
    expect(parsed.groupPolicy).toBe("allowlist");
  });

  it('rejects dmPolicy="open" without allowFrom including "*"', () => {
    const result = PulseBoardAccountSchema.safeParse({
      dmPolicy: "open",
    });
    expect(result.success).toBe(false);
  });
});

describe("PulseBoardAccountSchemaBase", () => {
  it("exposes textChunkLimit up to 4000", () => {
    const parsed = PulseBoardAccountSchemaBase.parse({ textChunkLimit: 4000 });
    expect(parsed.textChunkLimit).toBe(4000);
  });
});

describe("PulseBoardChannelConfigSchema", () => {
  it("accepts valid pulseboard channel config", () => {
    const result = PulseBoardChannelConfigSchema.safeParse({
      serverUrl: "https://boards.example.com",
      apiToken: "tok-abc123",
    });
    expect(result.success).toBe(true);
  });

  it("accepts empty config", () => {
    const result = PulseBoardChannelConfigSchema.safeParse({});
    expect(result.success).toBe(true);
  });
});

