import { afterEach, beforeEach, describe, expect, it } from "vitest";
import {
  listEnabledPulseBoardAccounts,
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

function asConfig(value: unknown): CoreConfig {
  return value as CoreConfig;
}

// Save and restore PULSEBOARD_API_TOKEN around env-sensitive tests.
let savedApiToken: string | undefined;

beforeEach(() => {
  savedApiToken = process.env.PULSEBOARD_API_TOKEN;
  delete process.env.PULSEBOARD_API_TOKEN;
});

afterEach(() => {
  if (savedApiToken === undefined) {
    delete process.env.PULSEBOARD_API_TOKEN;
  } else {
    process.env.PULSEBOARD_API_TOKEN = savedApiToken;
  }
});

describe("listPulseBoardAccountIds", () => {
  it("returns [default] when no accounts are configured", () => {
    expect(listPulseBoardAccountIds(asConfig({}))).toEqual(["default"]);
  });

  it("returns [default] when pulseboard section exists but has no accounts key", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          serverUrl: "https://boards.example.com",
          apiToken: "tok-abc",
        },
      },
    });
    expect(listPulseBoardAccountIds(cfg)).toEqual(["default"]);
  });

  it("normalizes, deduplicates, and sorts configured account ids", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          accounts: {
            "Ops Team": {},
            "ops-team": {},
            Work: {},
          },
        },
      },
    });
    expect(listPulseBoardAccountIds(cfg)).toEqual(["ops-team", "work"]);
  });

  it("includes default alongside named accounts", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          accounts: {
            default: {},
            work: {},
          },
        },
      },
    });
    const ids = listPulseBoardAccountIds(cfg);
    expect(ids).toContain("default");
    expect(ids).toContain("work");
  });
});

describe("resolveDefaultPulseBoardAccountId", () => {
  it("returns default when no accounts configured", () => {
    expect(resolveDefaultPulseBoardAccountId(asConfig({}))).toBe("default");
  });

  it("prefers configured defaultAccount when it matches an account", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          defaultAccount: "Ops Team",
          accounts: {
            default: {},
            "ops-team": {},
          },
        },
      },
    });
    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("ops-team");
  });

  it("falls back to default when configured defaultAccount is missing", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          defaultAccount: "missing",
          accounts: {
            default: {},
            work: {},
          },
        },
      },
    });
    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("default");
  });

  it("falls back to first sorted account when default is absent", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          accounts: {
            zzz: {},
            aaa: {},
          },
        },
      },
    });
    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("aaa");
  });
});

describe("resolvePulseBoardAccount", () => {
  it("resolves a fully configured default account", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          serverUrl: "https://boards.example.com",
          apiToken: "tok-abc123",
          username: "claw-bot",
          name: "Main Account",
        },
      },
    });
    const account = resolvePulseBoardAccount({ cfg });

    expect(account.accountId).toBe("default");
    expect(account.serverUrl).toBe("https://boards.example.com");
    expect(account.apiToken).toBe("tok-abc123");
    expect(account.username).toBe("claw-bot");
    expect(account.name).toBe("Main Account");
    expect(account.configured).toBe(true);
    expect(account.enabled).toBe(true);
    expect(account.apiTokenSource).toBe("config");
  });

