import { describe, expect, it } from "vitest";
import { pulseBoardPlugin } from "./channel.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import type { CoreConfig } from "./types.js";

function asConfig(value: unknown): CoreConfig {
  return value as CoreConfig;
}

function makeConfiguredCfg(
  overrides: Record<string, unknown> = {},
): CoreConfig {
  return asConfig({
    channels: {
      pulseboard: {
        serverUrl: "https://boards.example.com",
        apiToken: "tok-abc123",
        ...overrides,
      },
    },
  });
}

function requireNormalizeTarget() {
  const fn = pulseBoardPlugin.messaging?.normalizeTarget;
  if (!fn) throw new Error("pulseBoardPlugin.messaging.normalizeTarget missing");
  return fn;
}

function requireLooksLikeId() {
  const fn = pulseBoardPlugin.messaging?.targetResolver?.looksLikeId;
  if (!fn) throw new Error("pulseBoardPlugin.messaging.targetResolver.looksLikeId missing");
  return fn;
}

function requireResolveDmPolicy() {
  const fn = pulseBoardPlugin.security?.resolveDmPolicy;
  if (!fn) throw new Error("pulseBoardPlugin.security.resolveDmPolicy missing");
  return fn;
}

function requirePairingNormalizer() {
  const fn = pulseBoardPlugin.pairing?.normalizeAllowEntry;
  if (!fn) throw new Error("pulseBoardPlugin.pairing.normalizeAllowEntry missing");
  return fn;
}

describe("pulseBoardPlugin", () => {
  describe("meta", () => {
    it("has correct id", () => {
      expect(pulseBoardPlugin.id).toBe("pulseboard");
    });

    it("has required meta fields", () => {
      expect(pulseBoardPlugin.meta.label).toBe("PulseBoard");
      expect(pulseBoardPlugin.meta.docsPath).toBe("/channels/pulseboard");
    });

    it("has a non-empty blurb", () => {
      expect(pulseBoardPlugin.meta.blurb.length).toBeGreaterThan(0);
    });
  });

  describe("capabilities", () => {
    it("supports direct messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("direct");
    });

    it("supports group messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("group");
    });

    it("does not support media", () => {
      expect(pulseBoardPlugin.capabilities.media).toBe(false);
    });

    it("does not block streaming", () => {
      expect(pulseBoardPlugin.capabilities.blockStreaming).toBe(false);
    });
  });

  describe("config adapter", () => {
    it("listAccountIds returns [default] for empty config", () => {
      const cfg = asConfig({});
      const ids = pulseBoardPlugin.config.listAccountIds(cfg);
      expect(ids).toEqual(["default"]);
    });

    it("listAccountIds returns named accounts", () => {
      const cfg = asConfig({
        channels: {
          pulseboard: {
            accounts: {
              work: {},
              personal: {},
            },
          },
        },
      });
      const ids = pulseBoardPlugin.config.listAccountIds(cfg);
      expect(ids).toContain("work");
      expect(ids).toContain("personal");
    });

    it("resolveAccount returns a configured account", () => {
      const cfg = makeConfiguredCfg();
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      expect(account.configured).toBe(true);
      expect(account.serverUrl).toBe("https://boards.example.com");
    });

    it("resolveAccount returns unconfigured when missing credentials", () => {
      const cfg = asConfig({});
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      expect(account.configured).toBe(false);
    });

    it("isConfigured returns true for a configured account", () => {
      const cfg = makeConfiguredCfg();
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      expect(pulseBoardPlugin.config.isConfigured(account)).toBe(true);
    });

    it("isConfigured returns false for an unconfigured account", () => {
      const cfg = asConfig({});
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      expect(pulseBoardPlugin.config.isConfigured(account)).toBe(false);
    });
